import android.view.LayoutInflater\nimport android.view.ViewGroup\nimport androidx.recyclerview.widget.RecyclerView\nimport com.example.qwenneon.R\nimport com.example.qwenneon.models.ChatMessage\nimport com.example.qwenneon.viewholders.AIMessageViewHolder\nimport com.example.qwenneon.viewholders.UserMessageViewHolder\n\nclass ChatMessageAdapter(private val messages: List<ChatMessage>) : RecyclerView.Adapter<RecyclerView.ViewHolder>() {\n\n    companion object {\n        private const val VIEW_TYPE_USER = 1\n        private const val VIEW_TYPE_AI = 2\n    }\n\n    override fun getItemCount(): Int {\n        return messages.size\n    }\n\n    override fun getItemViewType(position: Int): Int {\n        return if (messages[position].isUser) VIEW_TYPE_USER else VIEW_TYPE_AI\n    }\n\n    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): RecyclerView.ViewHolder {\n        return when (viewType) {\n            VIEW_TYPE_USER -> {\n                val view = LayoutInflater.from(parent.context).inflate(R.layout.item_user_message, parent, false)\n                UserMessageViewHolder(view)\n            }\n            VIEW_TYPE_AI -> {\n                val view = LayoutInflater.from(parent.context).inflate(R.layout.item_ai_message, parent, false)\n                AIMessageViewHolder(view)\n            }\n            else -> throw IllegalArgumentException("Unexpected view type: " + viewType)\n        }\n    }\n\n    override fun onBindViewHolder(holder: RecyclerView.ViewHolder, position: Int) {\n        val message = messages[position]\n        if (holder is UserMessageViewHolder) {\n            holder.bind(message)\n        } else if (holder is AIMessageViewHolder) {\n            holder.bind(message)\n        }\n    }\n}